#include <stdio.h>
int main() {
    int T, N, A[1000000], swaps;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < 2 * N; i++) {
            scanf("%d", &A[i]);
        }
        swaps = 0;
        for (int i = 0; i < 2 * N - 1; i++) {
            if (A[i] != A[i + 1]) {
                int j = i + 1;
                while (A[i] != A[j]) {
                    j++;
                }
                while (j > i + 1) {
                    int temp = A[j];
                    A[j] = A[j - 1];
                    A[j - 1] = temp;
                    j--;
                    swaps++;
                }
            }
        }
        printf("%d\n", swaps);
    }
    return 0;
}

