import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[2 * N];
            for (int i = 0; i < 2 * N; i++) {
                A[i] = sc.nextInt();
            }
            int swaps = 0;
            for (int i = 0; i < 2 * N - 1; i++) {
                if (A[i] != A[i + 1]) {
                    int j = i + 1;
                    while (A[i] != A[j]) {
                        j++;
                    }
                    while (j > i + 1) {
                        int temp = A[j];
                        A[j] = A[j - 1];
                        A[j - 1] = temp;
                        j--;
                        swaps++;
                    }
                }
            }
            System.out.println(swaps);
        }
    }
}

